// src/components/auth/LoginPage.jsx
// Two separate login portals – intern and supervisor – shown side-by-side on
// desktop and as tab-switched cards on mobile.
import { useState } from "react";
import { useAuth } from "../../hooks/useAuth";
import logoImg from "../../assets/logo.png";

// ── Shared login card ─────────────────────────────────────────────────────────
function LoginCard({ role, accentColor, icon, title, subtitle }) {
  const { login }              = useAuth();
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [error,    setError]    = useState("");
  const [loading,  setLoading]  = useState(false);

  const handle = async () => {
    if (!username || !password) { setError("Please enter username and password."); return; }
    setLoading(true); setError("");
    try { await login(username, password, role); }
    catch (e) { setError(e.message || "Invalid credentials."); setLoading(false); }
  };

  return (
    <div style={{
      background: "rgba(255,255,255,.97)",
      borderRadius: 22,
      padding: "38px 36px",
      width: 360,
      maxWidth: "100%",
      boxShadow: "0 24px 80px rgba(0,0,0,.32)",
      position: "relative",
      zIndex: 1,
      borderTop: `4px solid ${accentColor}`,
    }}>
      {/* Header */}
      <div style={{ textAlign:"center", marginBottom:20 }}>
        <div style={{ fontSize:36, marginBottom:8 }}>{icon}</div>
        <h2 style={{ fontFamily:"Syne,sans-serif", fontSize:22, fontWeight:800, color:"#0a2e1a", marginBottom:4 }}>{title}</h2>
        <p style={{ fontSize:12, color:"#6b7280" }}>{subtitle}</p>
      </div>

      {error && (
        <div style={{ background:"#fef2f2", border:"1px solid #fecaca", borderRadius:8, padding:"8px 12px", marginBottom:14, fontSize:12, color:"#dc2626", display:"flex", alignItems:"center", gap:6 }}>
          ⚠️ {error}
        </div>
      )}

      <div style={{ marginBottom:14 }}>
        <label style={{ fontSize:12, fontWeight:600, color:"#374151", display:"block", marginBottom:5 }}>Username</label>
        <input
          style={{ width:"100%", padding:"10px 14px", border:"1.5px solid #e5e7eb", borderRadius:9, fontSize:13, fontFamily:"inherit", outline:"none", boxSizing:"border-box", transition:"border .2s" }}
          value={username}
          onChange={e => setUsername(e.target.value)}
          onFocus={e => e.target.style.borderColor = accentColor}
          onBlur={e => e.target.style.borderColor = "#e5e7eb"}
          placeholder={`Enter ${role} username`}
          onKeyDown={e => e.key === "Enter" && handle()}
          autoComplete="username"
        />
      </div>

      <div style={{ marginBottom:20 }}>
        <label style={{ fontSize:12, fontWeight:600, color:"#374151", display:"block", marginBottom:5 }}>Password</label>
        <input
          style={{ width:"100%", padding:"10px 14px", border:"1.5px solid #e5e7eb", borderRadius:9, fontSize:13, fontFamily:"inherit", outline:"none", boxSizing:"border-box", transition:"border .2s" }}
          type="password"
          value={password}
          onChange={e => setPassword(e.target.value)}
          onFocus={e => e.target.style.borderColor = accentColor}
          onBlur={e => e.target.style.borderColor = "#e5e7eb"}
          placeholder="Enter your password"
          onKeyDown={e => e.key === "Enter" && handle()}
          autoComplete="current-password"
        />
      </div>

      <button
        onClick={handle}
        disabled={loading}
        style={{
          width:"100%", padding:"11px", borderRadius:10, border:"none",
          background: loading ? "#9ca3af" : `linear-gradient(135deg,${accentColor},${accentColor}cc)`,
          color:"white", fontSize:14, fontWeight:700, fontFamily:"inherit",
          cursor: loading ? "not-allowed" : "pointer",
          transition:"all .2s",
          boxShadow: loading ? "none" : `0 4px 14px ${accentColor}44`,
        }}
      >
        {loading ? "Signing in…" : `Sign In as ${title} →`}
      </button>
    </div>
  );
}

// ── Main login page ───────────────────────────────────────────────────────────
export default function LoginPage() {
  const [activeTab, setActiveTab] = useState("intern");

  return (
    <div style={{
      minHeight: "100vh",
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      justifyContent: "center",
      background: "linear-gradient(145deg,#051a0e 0%,#0a2e1a 40%,#155030 100%)",
      position: "relative",
      overflow: "hidden",
      padding: 24,
      gap: 32,
    }}>
      {/* Background blobs */}
      <div style={{ position:"absolute", width:500, height:500, borderRadius:"50%", background:"radial-gradient(circle,rgba(46,204,122,.15),transparent 70%)", top:-100, right:-100, pointerEvents:"none" }}/>
      <div style={{ position:"absolute", width:400, height:400, borderRadius:"50%", background:"radial-gradient(circle,rgba(212,168,67,.1),transparent 70%)", bottom:-80, left:-80, pointerEvents:"none" }}/>

      {/* Logo & branding */}
      <div style={{ textAlign:"center", zIndex:1 }}>
        <img src={logoImg} alt="EGI" style={{ width:80, height:90, objectFit:"contain", borderRadius:12, marginBottom:10 }}/>
        <div style={{ fontFamily:"Syne,sans-serif", fontSize:22, fontWeight:900, color:"white", letterSpacing:".3px" }}>Eco Green International</div>
        <div style={{ fontSize:11, color:"rgba(255,255,255,.5)", letterSpacing:"1px", textTransform:"uppercase", marginTop:4 }}>Intern Training Programme 2025 / 2026</div>
      </div>

      {/* ── Desktop: side-by-side cards ── */}
      <div style={{ display:"flex", gap:28, flexWrap:"wrap", justifyContent:"center", zIndex:1 }}>
        <LoginCard
          role="intern"
          accentColor="#2ecc7a"
          icon="👨‍💻"
          title="Intern"
          subtitle="Sign in to your internship portal"
        />
        <LoginCard
          role="supervisor"
          accentColor="#d4a843"
          icon="👔"
          title="Supervisor"
          subtitle="Access the management dashboard"
        />
      </div>

      <p style={{ color:"rgba(255,255,255,.3)", fontSize:11, zIndex:1, textAlign:"center" }}>
        © 2026 Eco Green International Pvt Ltd · All rights reserved
      </p>
    </div>
  );
}
